#[component]
pub fn Technologies() -> impl IntoView {
    let technologies = get_technologies();
    let mut duplicate = Vec::new();
    for _ in 0..5 {
        duplicate.extend_from_slice(&technologies);
    }

    view! {
        <div class="overflow-hidden w-full">
            <div class="tech-carousel flex flex-row items-center justify-center space-x-10 py-8">
                {duplicate.iter().enumerate().map(|(index, tech)| {
                    let svg = tech.svg;
                    let name = tech.name;
                    view! {
                        <div
                            class="flex flex-col items-center justify-center text-white text-semibold text-2xl m-6 hover:scale-125 transition-transform"
                        >
                            {name}
                            <div inner_html=svg class="text-6xl text-white w-16 h-16"></div>
                        </div>
                    }
                }).collect::<Vec<_>>()}
            </div>
        </div>
    }
}
